# token F1 function
def token_f1(a,b):
    atoks = a.split()
    btoks = b.split()
    common = sum(min(atoks.count(t), btoks.count(t)) for t in set(atoks))
    if common == 0:
        return 0.0
    prec = common / len(btoks)
    rec = common / len(atoks)
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

